/**
 * Demo data generators for the frontend
 * Creates realistic test data for the solver
 */

import type { Asset, MaintenanceType, SolverInput, SolverEvent, Depot, ResourceConstraints } from "@uptime/types";

export const maintenanceTypes: MaintenanceType[] = [
  {
    id: "mt-a",
    level: "A",
    name: "A-Check",
    intervalKm: 10000,
    toleranceKm: 2000,
    durationHours: 4,
    manHours: 8,
    requiredTracks: 1,
    estimatedCost: 2500,
  },
  {
    id: "mt-b",
    level: "B",
    name: "B-Check",
    intervalKm: 50000,
    toleranceKm: 5000,
    durationHours: 16,
    manHours: 32,
    requiredTracks: 1,
    estimatedCost: 8500,
  },
  {
    id: "mt-c",
    level: "C",
    name: "C-Check",
    intervalKm: 200000,
    toleranceKm: 20000,
    durationHours: 72,
    manHours: 160,
    requiredTracks: 1,
    estimatedCost: 45000,
  },
  {
    id: "mt-d",
    level: "D",
    name: "D-Overhaul",
    intervalKm: 800000,
    toleranceKm: 50000,
    durationHours: 480,
    manHours: 1200,
    requiredTracks: 2,
    estimatedCost: 180000,
  },
];

export const depots: Depot[] = [
  {
    id: "depot-main",
    name: "Main Depot",
    assetTypes: ["TYPE_A", "TYPE_B"],
    trackCount: 4,
    weeklyManHours: 2200,
  },
  {
    id: "depot-secondary",
    name: "Secondary Depot",
    assetTypes: ["TYPE_A"],
    trackCount: 3,
    weeklyManHours: 1800,
  },
  {
    id: "depot-auxiliary",
    name: "Auxiliary Depot",
    assetTypes: ["TYPE_B"],
    trackCount: 2,
    weeklyManHours: 1200,
  },
];

export const defaultConstraints: ResourceConstraints = {
  weeklyManHours: 5200,
  monthlyManHours: 20800,
  maintenanceTracks: 9,
  trackCapacityPerDay: 2,
  depots,
};

export function generateFleet(count: number): Asset[] {
  const assets: Asset[] = [];

  for (let i = 0; i < count; i++) {
    const isTypeA = i < Math.ceil(count * 0.6); // 60% Type A
    const phaseOffsetKm = (i % 10) * 1000;
    const currentKm = 500000 + (i % 20) * 5000;

    assets.push({
      id: `ASSET-${isTypeA ? "A" : "B"}-${String(i + 1).padStart(3, "0")}`,
      assetNumber: `ASSET-${isTypeA ? "A" : "B"}-${String(i + 1).padStart(3, "0")}`,
      assetType: isTypeA ? "TYPE_A" : "TYPE_B",
      carsCount: 5,
      currentMileageKm: currentKm,
      avgDailyMileageKm: 450 + (i % 10) * 5,
      lastMaintenanceDate: "2025-01-01",
      status: "operational",
      lastMaintenanceKm: {
        "mt-a": currentKm - phaseOffsetKm,
        "mt-b": currentKm - (i % 15) * 3000,
        "mt-c": currentKm - (i % 25) * 8000,
        "mt-d": currentKm - (i % 40) * 20000,
      },
    });
  }

  return assets;
}

export function generateEvents(
  assets: Asset[],
  horizonWeeks: number
): SolverEvent[] {
  const events: SolverEvent[] = [];
  let eventId = 0;

  for (const asset of assets) {
    for (const mt of maintenanceTypes) {
      const currentKm = asset.currentMileageKm;
      const lastMtKm = asset.lastMaintenanceKm?.[mt.id] ?? currentKm - mt.intervalKm;
      const nextDueKm = lastMtKm + mt.intervalKm;

      const weeklyKm = asset.avgDailyMileageKm * 7;
      const weeksUntilDue = Math.max(0, Math.floor((nextDueKm - currentKm) / weeklyKm));

      if (weeksUntilDue < horizonWeeks) {
        const toleranceWeeks = Math.floor(mt.toleranceKm / weeklyKm);
        events.push({
          id: `evt-${String(eventId++).padStart(5, "0")}`,
          assetId: asset.id,
          maintenanceTypeId: mt.id,
          manHours: mt.manHours,
          earliestPeriod: Math.max(0, weeksUntilDue - toleranceWeeks),
          latestPeriod: Math.min(horizonWeeks - 1, weeksUntilDue + toleranceWeeks),
          targetPeriod: weeksUntilDue,
          priority: mt.level === "A" || mt.level === "B" ? 5 : 7,
        });
      }
    }
  }

  return events;
}

export function createSolverInput(
  fleetSize: number,
  horizonWeeks: number,
  capacity?: number
): SolverInput {
  const assets = generateFleet(fleetSize);
  const events = generateEvents(assets, horizonWeeks);
  const constraints = { ...defaultConstraints };

  if (capacity) {
    constraints.weeklyManHours = capacity;
  }

  return {
    events,
    assets,
    maintenanceTypes,
    constraints,
    planningHorizonWeeks: horizonWeeks,
    objective: {
      peakWorkloadWeight: 1.0,
      levelingWeight: 0.5,
      complianceWeight: 0.3,
    },
    settings: {
      timeoutSeconds: 60,
      gapTolerance: 0.01,
    },
  };
}

