import { useState, useCallback } from "react";
import type { MetaFunction } from "react-router";
import ContentLayout from "@cloudscape-design/components/content-layout";
import Header from "@cloudscape-design/components/header";
import Container from "@cloudscape-design/components/container";
import SpaceBetween from "@cloudscape-design/components/space-between";
import Button from "@cloudscape-design/components/button";
import Form from "@cloudscape-design/components/form";
import FormField from "@cloudscape-design/components/form-field";
import Input from "@cloudscape-design/components/input";
import Select from "@cloudscape-design/components/select";
import Slider from "@cloudscape-design/components/slider";
import Grid from "@cloudscape-design/components/grid";
import Box from "@cloudscape-design/components/box";
import ColumnLayout from "@cloudscape-design/components/column-layout";
import StatusIndicator from "@cloudscape-design/components/status-indicator";
import Alert from "@cloudscape-design/components/alert";
import ProgressBar from "@cloudscape-design/components/progress-bar";
import BarChart from "@cloudscape-design/components/bar-chart";
import type { SolverOutput } from "@uptime/types";
import { solveSchedule } from "~/lib/api";
import { createSolverInput } from "~/lib/demo-data";

export const meta: MetaFunction = () => {
  return [
    { title: "What-If Simulator - Fleet Maintenance" },
    { name: "description", content: "Simulate scheduling scenarios" },
  ];
};

function ValueWithLabel({ label, value }: { label: string; value: React.ReactNode }) {
  return (
    <div>
      <Box variant="awsui-key-label">{label}</Box>
      <div>{value}</div>
    </div>
  );
}

type HorizonOption = { label: string; value: string };
type FleetOption = { label: string; value: string };
type PriorityOption = { label: string; value: string };

export default function WhatIf() {
  const [isRunning, setIsRunning] = useState(false);
  const [result, setResult] = useState<SolverOutput | null>(null);
  const [error, setError] = useState<string | null>(null);

  // Form state
  const [scenarioName, setScenarioName] = useState("Baseline Scenario");
  const [capacity, setCapacity] = useState(5200);
  const [horizon, setHorizon] = useState<HorizonOption>({ label: "13 weeks (Quarter)", value: "13" });
  const [fleet, setFleet] = useState<FleetOption>({ label: "Full Fleet (128)", value: "128" });
  const [priority, setPriority] = useState<PriorityOption>({ label: "Balanced", value: "balanced" });

  const runSimulation = useCallback(async () => {
    setIsRunning(true);
    setError(null);
    setResult(null);

    try {
      const fleetSize = parseInt(fleet.value, 10);
      const horizonWeeks = parseInt(horizon.value, 10);
      const input = createSolverInput(fleetSize, horizonWeeks, capacity);

      const output = await solveSchedule(input);
      setResult(output);
    } catch (err) {
      setError(err instanceof Error ? err.message : "Unknown error");
    } finally {
      setIsRunning(false);
    }
  }, [capacity, horizon, fleet]);

  const resetForm = () => {
    setScenarioName("Baseline Scenario");
    setCapacity(5200);
    setHorizon({ label: "13 weeks (Quarter)", value: "13" });
    setFleet({ label: "Full Fleet (128)", value: "128" });
    setPriority({ label: "Balanced", value: "balanced" });
    setResult(null);
    setError(null);
  };

  // Prepare chart data from results
  const chartData = result?.solution?.workloadProfile.map((w) => ({
    x: `Week ${w.period + 1}`,
    y: w.manHours,
  })) || [];

  return (
    <ContentLayout
      header={
        <Header
          variant="h1"
          description="Test different scheduling scenarios and compare outcomes"
          info={
            <Box color="text-status-info" display="inline">
              Powered by HiGHS MIP Solver
            </Box>
          }
        >
          What-If Simulator
        </Header>
      }
    >
      <SpaceBetween size="l">
        <Alert type="info">
          Adjust parameters below to simulate different maintenance scenarios.
          The solver will optimize the schedule based on your constraints.
        </Alert>

        <Grid gridDefinition={[{ colspan: 5 }, { colspan: 7 }]}>
          <Container header={<Header variant="h2">Scenario Parameters</Header>}>
            <Form
              actions={
                <SpaceBetween direction="horizontal" size="xs">
                  <Button variant="link" onClick={resetForm}>Reset</Button>
                  <Button
                    variant="primary"
                    loading={isRunning}
                    onClick={runSimulation}
                  >
                    {isRunning ? "Running Solver..." : "Run Simulation"}
                  </Button>
                </SpaceBetween>
              }
            >
              <SpaceBetween size="l">
                <FormField label="Scenario Name">
                  <Input
                    value={scenarioName}
                    onChange={({ detail }) => setScenarioName(detail.value)}
                  />
                </FormField>

                <FormField label="Planning Horizon">
                  <Select
                    selectedOption={horizon}
                    onChange={({ detail }) => setHorizon(detail.selectedOption as HorizonOption)}
                    options={[
                      { label: "13 weeks (Quarter)", value: "13" },
                      { label: "26 weeks (Half Year)", value: "26" },
                      { label: "52 weeks (Full Year)", value: "52" },
                    ]}
                  />
                </FormField>

                <FormField
                  label="Weekly Capacity (man-hours)"
                  description={`Current: ${capacity.toLocaleString()} man-hours/week`}
                >
                  <Slider
                    value={capacity}
                    onChange={({ detail }) => setCapacity(detail.value)}
                    min={3000}
                    max={8000}
                    step={100}
                  />
                </FormField>

                <FormField label="Optimization Priority">
                  <Select
                    selectedOption={priority}
                    onChange={({ detail }) => setPriority(detail.selectedOption as PriorityOption)}
                    options={[
                      { label: "Minimize Peak Workload", value: "peak" },
                      { label: "Maximize Compliance", value: "compliance" },
                      { label: "Balanced", value: "balanced" },
                      { label: "Minimize Cost", value: "cost" },
                    ]}
                  />
                </FormField>

                <FormField label="Fleet Selection">
                  <Select
                    selectedOption={fleet}
                    onChange={({ detail }) => setFleet(detail.selectedOption as FleetOption)}
                    options={[
                      { label: "Full Fleet (128)", value: "128" },
                      { label: "Medium Fleet (64)", value: "64" },
                      { label: "Small Fleet (20)", value: "20" },
                      { label: "Test Fleet (10)", value: "10" },
                    ]}
                  />
                </FormField>
              </SpaceBetween>
            </Form>
          </Container>

          <Container header={<Header variant="h2">Simulation Results</Header>}>
            {isRunning ? (
              <Box padding="l">
                <SpaceBetween size="l">
                  <ProgressBar
                    value={65}
                    label="Solver Progress"
                    description="Optimizing maintenance schedule..."
                    status="in-progress"
                  />
                  <Box color="text-body-secondary" textAlign="center">
                    Running HiGHS MIP solver...
                  </Box>
                </SpaceBetween>
              </Box>
            ) : error ? (
              <Alert type="error" header="Solver Error">
                {error}
              </Alert>
            ) : result ? (
              <SpaceBetween size="l">
                <Alert type={result.status === "OPTIMAL" ? "success" : result.status === "FEASIBLE" ? "info" : "warning"}>
                  <StatusIndicator type={result.status === "OPTIMAL" ? "success" : result.status === "FEASIBLE" ? "info" : "warning"}>
                    {result.status === "OPTIMAL"
                      ? `Optimal solution found in ${result.diagnostics.solveTimeMs.toFixed(0)}ms`
                      : result.status === "FEASIBLE"
                      ? `Feasible solution found in ${result.diagnostics.solveTimeMs.toFixed(0)}ms`
                      : `Status: ${result.status}`}
                  </StatusIndicator>
                </Alert>

                <ColumnLayout columns={2} variant="text-grid">
                  <ValueWithLabel
                    label="Solver Status"
                    value={
                      <StatusIndicator
                        type={result.status === "OPTIMAL" ? "success" : result.status === "FEASIBLE" ? "info" : "error"}
                      >
                        {result.status}
                      </StatusIndicator>
                    }
                  />
                  <ValueWithLabel
                    label="Solve Time"
                    value={`${result.diagnostics.solveTimeMs.toFixed(2)}ms`}
                  />
                  <ValueWithLabel
                    label="Events Scheduled"
                    value={result.solution?.assignments.length || 0}
                  />
                  <ValueWithLabel
                    label="Planning Horizon"
                    value={`${horizon.value} weeks`}
                  />
                </ColumnLayout>

                {result.metrics && (
                  <>
                    <Header variant="h3">Key Metrics</Header>
                    <ColumnLayout columns={2} variant="text-grid">
                      <ValueWithLabel
                        label="Peak Workload"
                        value={`${result.metrics.peakWorkload.toLocaleString()} man-hours (${Math.round(result.metrics.peakWorkload / capacity * 100)}% capacity)`}
                      />
                      <ValueWithLabel
                        label="Average Workload"
                        value={`${result.metrics.averageWorkload.toLocaleString()} man-hours (${Math.round(result.metrics.averageWorkload / capacity * 100)}% capacity)`}
                      />
                      <ValueWithLabel
                        label="Workload Variance (CV)"
                        value={
                          <StatusIndicator type={result.metrics.workloadCv < 0.3 ? "success" : result.metrics.workloadCv < 0.5 ? "warning" : "error"}>
                            {(result.metrics.workloadCv * 100).toFixed(1)}%
                          </StatusIndicator>
                        }
                      />
                      <ValueWithLabel
                        label="Compliance Rate"
                        value={
                          <StatusIndicator type={result.metrics.complianceRate > 0.9 ? "success" : result.metrics.complianceRate > 0.7 ? "warning" : "error"}>
                            {(result.metrics.complianceRate * 100).toFixed(1)}%
                          </StatusIndicator>
                        }
                      />
                    </ColumnLayout>
                  </>
                )}

                <SpaceBetween direction="horizontal" size="xs">
                  <Button>Export Results</Button>
                  <Button>Compare Scenarios</Button>
                  <Button variant="primary">Apply to Schedule</Button>
                </SpaceBetween>
              </SpaceBetween>
            ) : (
              <Box color="text-body-secondary" textAlign="center" padding="l">
                <SpaceBetween size="m">
                  <Box variant="h3">No Results Yet</Box>
                  <Box>
                    Configure your scenario parameters and click "Run Simulation"
                    to see optimization results.
                  </Box>
                </SpaceBetween>
              </Box>
            )}
          </Container>
        </Grid>

        {result?.solution && (
          <Container
            header={
              <Header
                variant="h2"
                description="Weekly workload distribution for the optimized schedule"
              >
                Workload Distribution
              </Header>
            }
          >
            <BarChart
              series={[
                {
                  title: "Man-Hours",
                  type: "bar",
                  data: chartData,
                },
                {
                  title: "Capacity",
                  type: "threshold",
                  y: capacity,
                },
              ]}
              xDomain={chartData.map((d) => d.x)}
              yDomain={[0, Math.max(capacity * 1.2, ...chartData.map((d) => d.y))]}
              yTitle="Man-Hours"
              xTitle="Week"
              height={300}
              hideFilter
              statusType="finished"
            />
          </Container>
        )}
      </SpaceBetween>
    </ContentLayout>
  );
}

/**
 * Demo data generators for the frontend
 * Creates realistic test data for the solver
 */

import type { Asset, MaintenanceType, SolverInput, SolverEvent, Depot, ResourceConstraints } from "@uptime/types";

export const maintenanceTypes: MaintenanceType[] = [
  {
    id: "mt-a",
    level: "A",
    name: "A-Check",
    intervalKm: 10000,
    toleranceKm: 2000,
    durationHours: 4,
    manHours: 8,
    requiredTracks: 1,
    estimatedCost: 2500,
  },
  {
    id: "mt-b",
    level: "B",
    name: "B-Check",
    intervalKm: 50000,
    toleranceKm: 5000,
    durationHours: 16,
    manHours: 32,
    requiredTracks: 1,
    estimatedCost: 8500,
  },
  {
    id: "mt-c",
    level: "C",
    name: "C-Check",
    intervalKm: 200000,
    toleranceKm: 20000,
    durationHours: 72,
    manHours: 160,
    requiredTracks: 1,
    estimatedCost: 45000,
  },
  {
    id: "mt-d",
    level: "D",
    name: "D-Overhaul",
    intervalKm: 800000,
    toleranceKm: 50000,
    durationHours: 480,
    manHours: 1200,
    requiredTracks: 2,
    estimatedCost: 180000,
  },
];

export const depots: Depot[] = [
  {
    id: "depot-main",
    name: "Main Depot",
    assetTypes: ["TYPE_A", "TYPE_B"],
    trackCount: 4,
    weeklyManHours: 2200,
  },
  {
    id: "depot-secondary",
    name: "Secondary Depot",
    assetTypes: ["TYPE_A"],
    trackCount: 3,
    weeklyManHours: 1800,
  },
  {
    id: "depot-auxiliary",
    name: "Auxiliary Depot",
    assetTypes: ["TYPE_B"],
    trackCount: 2,
    weeklyManHours: 1200,
  },
];

export const defaultConstraints: ResourceConstraints = {
  weeklyManHours: 5200,
  monthlyManHours: 20800,
  maintenanceTracks: 9,
  trackCapacityPerDay: 2,
  depots,
};

export function generateFleet(count: number): Asset[] {
  const assets: Asset[] = [];

  for (let i = 0; i < count; i++) {
    const isTypeA = i < Math.ceil(count * 0.6); // 60% Type A
    const phaseOffsetKm = (i % 10) * 1000;
    const currentKm = 500000 + (i % 20) * 5000;

    assets.push({
      id: `ASSET-${isTypeA ? "A" : "B"}-${String(i + 1).padStart(3, "0")}`,
      assetNumber: `ASSET-${isTypeA ? "A" : "B"}-${String(i + 1).padStart(3, "0")}`,
      assetType: isTypeA ? "TYPE_A" : "TYPE_B",
      carsCount: 5,
      currentMileageKm: currentKm,
      avgDailyMileageKm: 450 + (i % 10) * 5,
      lastMaintenanceDate: "2025-01-01",
      status: "operational",
      lastMaintenanceKm: {
        "mt-a": currentKm - phaseOffsetKm,
        "mt-b": currentKm - (i % 15) * 3000,
        "mt-c": currentKm - (i % 25) * 8000,
        "mt-d": currentKm - (i % 40) * 20000,
      },
    });
  }

  return assets;
}

export function generateEvents(
  assets: Asset[],
  horizonWeeks: number
): SolverEvent[] {
  const events: SolverEvent[] = [];
  let eventId = 0;

  for (const asset of assets) {
    for (const mt of maintenanceTypes) {
      const currentKm = asset.currentMileageKm;
      const lastMtKm = asset.lastMaintenanceKm?.[mt.id] ?? currentKm - mt.intervalKm;
      const nextDueKm = lastMtKm + mt.intervalKm;

      const weeklyKm = asset.avgDailyMileageKm * 7;
      const weeksUntilDue = Math.max(0, Math.floor((nextDueKm - currentKm) / weeklyKm));

      if (weeksUntilDue < horizonWeeks) {
        const toleranceWeeks = Math.floor(mt.toleranceKm / weeklyKm);
        events.push({
          id: `evt-${String(eventId++).padStart(5, "0")}`,
          assetId: asset.id,
          maintenanceTypeId: mt.id,
          manHours: mt.manHours,
          earliestPeriod: Math.max(0, weeksUntilDue - toleranceWeeks),
          latestPeriod: Math.min(horizonWeeks - 1, weeksUntilDue + toleranceWeeks),
          targetPeriod: weeksUntilDue,
          priority: mt.level === "A" || mt.level === "B" ? 5 : 7,
        });
      }
    }
  }

  return events;
}

export function createSolverInput(
  fleetSize: number,
  horizonWeeks: number,
  capacity?: number
): SolverInput {
  const assets = generateFleet(fleetSize);
  const events = generateEvents(assets, horizonWeeks);
  const constraints = { ...defaultConstraints };

  if (capacity) {
    constraints.weeklyManHours = capacity;
  }

  return {
    events,
    assets,
    maintenanceTypes,
    constraints,
    planningHorizonWeeks: horizonWeeks,
    objective: {
      peakWorkloadWeight: 1.0,
      levelingWeight: 0.5,
      complianceWeight: 0.3,
    },
    settings: {
      timeoutSeconds: 60,
      gapTolerance: 0.01,
    },
  };
}

