export interface Asset {
  id: string;
  assetNumber: string;
  assetType: AssetType;
  carsCount: number;
  currentMileageKm: number;
  lastMaintenanceDate: string; // ISO date
  status: AssetStatus;
  metadata?: Record<string, unknown>;
}

