  {
    id: "depot-main",
    name: "Main Depot",
    assetTypes: ["TYPE_A", "TYPE_B"],
    trackCount: 4,
    weeklyManHours: 2200,
  },
  {
    id: "depot-secondary",
    name: "Secondary Depot",
    assetTypes: ["TYPE_A"],
    trackCount: 3,
    weeklyManHours: 1800,
