  weeklyManHours: 5200,
  monthlyManHours: 20800,
  maintenanceTracks: 9,
  trackCapacityPerDay: 2,
  depots,
};

export function generateFleet(count: number): Asset[] {
  const assets: Asset[] = [];

  for (let i = 0; i < count; i++) {
    const isTypeA = i < Math.ceil(count * 0.6); // 60% Type A
    const phaseOffsetKm = (i % 10) * 1000;
    const currentKm = 500000 + (i % 20) * 5000;

    assets.push({
      id: `ASSET-${isTypeA ? "A" : "B"}-${String(i + 1).padStart(3, "0")}`,
