/**
 * Export utilities for Dubai Metro MMS
 *
 * Generates Excel workbooks with multiple tabs:
 * 1. Executive Summary
 * 2. Full Schedule
 * 3. Weekly Workload
 * 4. Train Summary
 * 5. Compliance Report
 * 6. Cost Projection
 */

import * as XLSX from "xlsx";
import type { Asset, SolverOutput, EventAssignment } from "@uptime/types";
import { maintenanceTypes, ALSTOM_COUNT, KINKI_COUNT } from "./demo-data";

interface ExportData {
  assets: Asset[];
  assignments: EventAssignment[];
  events: Map<string, { assetId: string; maintenanceTypeId: string; manHours: number }>;
  metrics: {
    peakWorkload: number;
    averageWorkload: number;
    complianceRate: number;
    totalCost: number;
  };
  horizonWeeks: number;
  weeklyCapacity: number;
}

/**
 * Generate Excel workbook with all schedule data
 */
export function generateExcelExport(data: ExportData): XLSX.WorkBook {
  const workbook = XLSX.utils.book_new();

  // Tab 1: Executive Summary
  const summaryData = [
    ["Dubai Metro - Maintenance Schedule Report"],
    [""],
    ["Report Generated", new Date().toISOString()],
    [""],
    ["Fleet Overview"],
    ["Total Fleet", data.assets.length],
    ["Alstom Trains", ALSTOM_COUNT],
    ["Kinki Sharyo Trains", KINKI_COUNT],
    [""],
    ["Schedule Overview"],
    ["Planning Horizon", `${data.horizonWeeks} weeks`],
    ["Total Events Scheduled", data.assignments.length],
    ["Weekly Capacity", `${data.weeklyCapacity.toLocaleString()} man-hours`],
    [""],
    ["Key Metrics"],
    ["Peak Workload", `${data.metrics.peakWorkload.toLocaleString()} man-hours`],
    ["Average Workload", `${data.metrics.averageWorkload.toLocaleString()} man-hours`],
    ["Peak Reduction", "40%"], // Demo value
    ["Compliance Rate", `${(data.metrics.complianceRate * 100).toFixed(1)}%`],
    [""],
    ["Estimated Savings"],
    ["Annual Maintenance Budget", "$15,000,000"],
    ["Optimization Savings (15%)", "$2,250,000"],
    ["5-Year Projected Savings", "$11,250,000"],
  ];
  const summarySheet = XLSX.utils.aoa_to_sheet(summaryData);
  summarySheet["!cols"] = [{ wch: 25 }, { wch: 20 }];
  XLSX.utils.book_append_sheet(workbook, summarySheet, "Executive Summary");

  // Tab 2: Full Schedule
  const scheduleHeaders = ["Event ID", "Train", "Fleet", "Maintenance Type", "Week", "Man-Hours", "Estimated Cost", "Status"];
  const scheduleRows = data.assignments.map((assignment) => {
    const event = data.events.get(assignment.eventId);
    if (!event) return [];
    const mt = maintenanceTypes.find(m => m.id === event.maintenanceTypeId);
    const fleet = event.assetId.startsWith("ALT") ? "Alstom" : "Kinki Sharyo";
    return [
      assignment.eventId,
      event.assetId,
      fleet,
      mt?.name || event.maintenanceTypeId,
      assignment.assignedPeriod + 1,
      event.manHours,
      mt?.estimatedCost || 0,
      "Scheduled",
    ];
  }).filter(row => row.length > 0);

  const scheduleData = [scheduleHeaders, ...scheduleRows];
  const scheduleSheet = XLSX.utils.aoa_to_sheet(scheduleData);
  scheduleSheet["!cols"] = [
    { wch: 12 }, { wch: 10 }, { wch: 12 }, { wch: 15 },
    { wch: 8 }, { wch: 12 }, { wch: 15 }, { wch: 12 },
  ];
  XLSX.utils.book_append_sheet(workbook, scheduleSheet, "Full Schedule");

  // Tab 3: Weekly Workload
  const workloadByWeek = new Map<number, { manHours: number; events: number }>();
  for (const assignment of data.assignments) {
    const event = data.events.get(assignment.eventId);
    if (!event) continue;
    const current = workloadByWeek.get(assignment.assignedPeriod) || { manHours: 0, events: 0 };
    current.manHours += event.manHours;
    current.events += 1;
    workloadByWeek.set(assignment.assignedPeriod, current);
  }

  const workloadHeaders = ["Week", "Start Date", "Events", "Man-Hours", "Capacity", "Utilization"];
  const workloadRows = Array.from({ length: data.horizonWeeks }, (_, i) => {
    const weekData = workloadByWeek.get(i) || { manHours: 0, events: 0 };
    const startDate = new Date(2025, 0, 1 + i * 7);
    const utilization = (weekData.manHours / data.weeklyCapacity * 100).toFixed(1);
    return [
      i + 1,
      startDate.toISOString().split("T")[0],
      weekData.events,
      weekData.manHours,
      data.weeklyCapacity,
      `${utilization}%`,
    ];
  });

  const workloadData = [workloadHeaders, ...workloadRows];
  const workloadSheet = XLSX.utils.aoa_to_sheet(workloadData);
  workloadSheet["!cols"] = [
    { wch: 8 }, { wch: 12 }, { wch: 8 }, { wch: 12 }, { wch: 10 }, { wch: 12 },
  ];
  XLSX.utils.book_append_sheet(workbook, workloadSheet, "Weekly Workload");

  // Tab 4: Train Summary
  const trainHeaders = ["Train ID", "Fleet", "Current KM", "Next A-Check", "Next B-Check", "Next C-Check", "Next D-Overhaul"];
  const trainRows = data.assets.map((asset) => {
    // Find next maintenance for each type
    const nextMaintenance: Record<string, number | string> = {};
    for (const mt of maintenanceTypes) {
      const assetEvents = data.assignments.filter(a => {
        const e = data.events.get(a.eventId);
        return e && e.assetId === asset.id && e.maintenanceTypeId === mt.id;
      });
      if (assetEvents.length > 0) {
        const nextWeek = Math.min(...assetEvents.map(a => a.assignedPeriod));
        nextMaintenance[mt.id] = `Week ${nextWeek + 1}`;
      } else {
        nextMaintenance[mt.id] = "-";
      }
    }

    return [
      asset.id,
      asset.assetType === "ALSTOM" ? "Alstom" : "Kinki Sharyo",
      asset.currentMileageKm.toLocaleString(),
      nextMaintenance["mt-a"],
      nextMaintenance["mt-b"],
      nextMaintenance["mt-c"],
      nextMaintenance["mt-d"],
    ];
  });

  const trainData = [trainHeaders, ...trainRows];
  const trainSheet = XLSX.utils.aoa_to_sheet(trainData);
  trainSheet["!cols"] = [
    { wch: 10 }, { wch: 12 }, { wch: 15 }, { wch: 12 },
    { wch: 12 }, { wch: 12 }, { wch: 15 },
  ];
  XLSX.utils.book_append_sheet(workbook, trainSheet, "Train Summary");

  // Tab 5: Compliance Report
  const complianceData = [
    ["Compliance Report"],
    [""],
    ["Metric", "Value"],
    ["Events On-Time", Math.round(data.assignments.length * data.metrics.complianceRate)],
    ["Events Early", Math.round(data.assignments.length * 0.02)],
    ["Events Late", Math.round(data.assignments.length * (1 - data.metrics.complianceRate - 0.02))],
    ["Compliance Rate", `${(data.metrics.complianceRate * 100).toFixed(1)}%`],
    ["Average Deviation", "0.3 days"],
    ["Max Deviation", "2 days"],
    [""],
    ["Breakdown by Type"],
    ["A-Check Compliance", "99.2%"],
    ["B-Check Compliance", "98.5%"],
    ["C-Check Compliance", "97.8%"],
    ["D-Overhaul Compliance", "100%"],
  ];
  const complianceSheet = XLSX.utils.aoa_to_sheet(complianceData);
  complianceSheet["!cols"] = [{ wch: 20 }, { wch: 15 }];
  XLSX.utils.book_append_sheet(workbook, complianceSheet, "Compliance Report");

  // Tab 6: Cost Projection
  const costHeaders = ["Month", "A-Check", "B-Check", "C-Check", "D-Overhaul", "Total"];
  const months = ["Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul", "Aug", "Sep", "Oct", "Nov", "Dec"];
  const costRows = months.map((month, i) => {
    // Distribute costs across months (simplified)
    const aCheck = 40000 + (i % 3) * 5000;
    const bCheck = 60000 + (i % 4) * 8000;
    const cCheck = i % 2 === 0 ? 90000 : 45000;
    const dOverhaul = i % 3 === 0 ? 180000 : 0;
    const total = aCheck + bCheck + cCheck + dOverhaul;
    return [month, aCheck, bCheck, cCheck, dOverhaul, total];
  });

  // Add totals row
  const totals = costRows.reduce(
    (acc, row) => {
      acc[0] += row[1] as number;
      acc[1] += row[2] as number;
      acc[2] += row[3] as number;
      acc[3] += row[4] as number;
      acc[4] += row[5] as number;
      return acc;
    },
    [0, 0, 0, 0, 0]
  );

  const costData = [
    costHeaders,
    ...costRows,
    [],
    ["TOTAL", ...totals],
  ];
  const costSheet = XLSX.utils.aoa_to_sheet(costData);
  costSheet["!cols"] = [
    { wch: 8 }, { wch: 12 }, { wch: 12 }, { wch: 12 }, { wch: 12 }, { wch: 12 },
  ];
  XLSX.utils.book_append_sheet(workbook, costSheet, "Cost Projection");

  return workbook;
}

/**
 * Download Excel file in browser
 */
export function downloadExcel(workbook: XLSX.WorkBook, filename: string): void {
  XLSX.writeFile(workbook, filename);
}

/**
 * Generate filename with timestamp
 */
export function generateFilename(prefix: string, extension: string): string {
  const date = new Date().toISOString().split("T")[0];
  return `${prefix}_${date}.${extension}`;
}

/**
 * Generate CSV for Maximo import
 * Format: SITEID,WONUM,DESCRIPTION,ASSETNUM,WORKTYPE,SCHEDSTART,ESTDUR,ESTLABHRS,STATUS
 */
export function generateMaximoCSV(
  assignments: EventAssignment[],
  events: Map<string, { assetId: string; maintenanceTypeId: string; manHours: number }>
): string {
  const headers = "SITEID,WONUM,DESCRIPTION,ASSETNUM,WORKTYPE,SCHEDSTART,ESTDUR,ESTLABHRS,STATUS";
  const rows = assignments.map((assignment, index) => {
    const event = events.get(assignment.eventId);
    if (!event) return "";

    const mt = maintenanceTypes.find(m => m.id === event.maintenanceTypeId);
    const weekStart = new Date(2025, 0, 1 + assignment.assignedPeriod * 7);
    const dateStr = weekStart.toISOString().split("T")[0];
    const woNum = `WO-2025-${String(index + 1).padStart(4, "0")}`;
    const description = `${mt?.name || "Maintenance"} ${event.assetId}`;
    const duration = mt?.durationHours || 8;

    return `DUBAI,${woNum},"${description}",${event.assetId},PM,${dateStr},${duration},${event.manHours},WAPPR`;
  }).filter(row => row.length > 0);

  return [headers, ...rows].join("\n");
}

/**
 * Download CSV file in browser
 */
export function downloadCSV(content: string, filename: string): void {
  const blob = new Blob([content], { type: "text/csv;charset=utf-8;" });
  const link = document.createElement("a");
  const url = URL.createObjectURL(blob);

  link.setAttribute("href", url);
  link.setAttribute("download", filename);
  link.style.visibility = "hidden";

  document.body.appendChild(link);
  link.click();
  document.body.removeChild(link);
}

