// Generate demo schedule data
function generateDemoSchedule() {
  const assets = generateFleet(TOTAL_FLEET);
  const events = generateEvents(assets, 52);

  // Create a map for quick event lookup
  const eventMap = new Map(events.map(e => [e.id, { assetId: e.assetId, maintenanceTypeId: e.maintenanceTypeId, manHours: e.manHours }]));

  // Simulate solver assignments (spread events across periods)
  const assignments: EventAssignment[] = events.map((event, index) => ({
    eventId: event.id,
    assignedPeriod: Math.min(event.latestPeriod, Math.max(event.earliestPeriod, event.targetPeriod + (index % 3) - 1)),
    deviation: 0,
  }));

  // Calculate metrics
  const workloadByWeek = new Map<number, number>();
  for (const assignment of assignments) {
    const event = eventMap.get(assignment.eventId);
    if (!event) continue;
    const current = workloadByWeek.get(assignment.assignedPeriod) || 0;
    workloadByWeek.set(assignment.assignedPeriod, current + event.manHours);
  }
  const workloads = Array.from(workloadByWeek.values());
  const peakWorkload = Math.max(...workloads);
  const averageWorkload = Math.round(workloads.reduce((a, b) => a + b, 0) / workloads.length);

  return {
    assets,
    assignments,
    events: eventMap,
    metrics: {
      peakWorkload,
      averageWorkload,
      complianceRate: 0.985,
      totalCost: 3156000,
    },
  };
}

