import { useState } from "react";
import { Outlet, useLocation, useNavigate } from "react-router";
import AppLayout from "@cloudscape-design/components/app-layout";
import SideNavigation from "@cloudscape-design/components/side-navigation";
import TopNavigation from "@cloudscape-design/components/top-navigation";
import BreadcrumbGroup from "@cloudscape-design/components/breadcrumb-group";

const navItems = [
  { type: "link" as const, text: "Dashboard", href: "/" },
  { type: "link" as const, text: "Fleet", href: "/fleet" },
  { type: "link" as const, text: "Schedule", href: "/schedule" },
  { type: "link" as const, text: "Calendar", href: "/calendar" },
  { type: "divider" as const },
  {
    type: "link" as const,
    text: "What-If Simulator",
    href: "/what-if",
    info: <span style={{ color: "#0972d3" }}>New</span>,
  },
];

const breadcrumbMap: Record<string, string> = {
  "/": "Dashboard",
  "/fleet": "Fleet Management",
  "/schedule": "Maintenance Schedule",
  "/calendar": "Maintenance Calendar",
  "/what-if": "What-If Simulator",
};

export default function Layout() {
  const location = useLocation();
  const navigate = useNavigate();
  const [navigationOpen, setNavigationOpen] = useState(true);

  const breadcrumbs = [
    { text: "MMS", href: "/" },
    ...(location.pathname !== "/"
      ? [{ text: breadcrumbMap[location.pathname] || "Page", href: location.pathname }]
      : []),
  ];

  return (
    <>
      <div id="top-nav">
        <TopNavigation
          identity={{
            href: "/",
            title: "Fleet Maintenance",
            logo: {
              src: "data:image/svg+xml,%3Csvg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 24 24' fill='%230972d3'%3E%3Cpath d='M12 2L2 7l10 5 10-5-10-5zM2 17l10 5 10-5M2 12l10 5 10-5'/%3E%3C/svg%3E",
              alt: "MMS",
            },
          }}
          utilities={[
            {
              type: "button",
              text: "Documentation",
              href: "/docs",
              external: true,
              externalIconAriaLabel: " (opens in new tab)",
            },
            {
              type: "menu-dropdown",
              text: "Settings",
              iconName: "settings",
              items: [
                { id: "preferences", text: "Preferences" },
                { id: "language", text: "Language" },
              ],
            },
            {
              type: "menu-dropdown",
              text: "Admin User",
              description: "admin@example.com",
              iconName: "user-profile",
              items: [
                { id: "profile", text: "Profile" },
                { id: "signout", text: "Sign out" },
              ],
            },
          ]}
        />
      </div>
      <AppLayout
        headerSelector="#top-nav"
        navigation={
          <SideNavigation
            activeHref={location.pathname}
            header={{ href: "/", text: "MMS" }}
            items={navItems}
            onFollow={(event) => {
              event.preventDefault();
              navigate(event.detail.href);
            }}
          />
        }
        navigationOpen={navigationOpen}
        onNavigationChange={({ detail }) => setNavigationOpen(detail.open)}
        breadcrumbs={
          <BreadcrumbGroup
            items={breadcrumbs}
            onFollow={(event) => {
              event.preventDefault();
              navigate(event.detail.href);
            }}
          />
        }
        content={<Outlet />}
        toolsHide
      />
    </>
  );
}

